// Fetching products from a headless Shopify backend
const response = await fetch(SHOPIFY_STOREFRONT_URL, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Shopify-Storefront-Access-Token': TOKEN,
  },
  body: JSON.stringify({
    query: `
      {
        products(first: 12) {
          edges {
            node {
              id
              title
              handle
              priceRange {
                minVariantPrice {
                  amount
                  currencyCode
                }
              }
              images(first: 1) {
                edges {
                  node { url altText }
                }
              }
            }
          }
        }
      }
    `
  }),
});

