// Bad: Blocking the main thread
button.addEventListener('click', () => {
  // Heavy computation that blocks UI
  const result = expensiveCalculation(data);
  updateDOM(result);
});

// Good: Using requestIdleCallback
button.addEventListener('click', () => {
  // Show immediate visual feedback
  showSpinner();
  requestIdleCallback(() => {
    const result = expensiveCalculation(data);
    updateDOM(result);
    hideSpinner();
  });
});
